script_template:
let outer_sphere = sphere(#{outer_radius});
let inner_sphere = sphere(#{outer_radius} - #{shell_thickness});
let shell = subtract(outer_sphere, inner_sphere);
let lattice = gyroid(#{cell_size}, #{strut_thickness});
let lattice_fill = intersect(inner_sphere, lattice);
let result = union(shell, lattice_fill);
result
